webpackJsonp([0x834755aae49e],{732:function(A,t){A.exports={data:{post:{id:"/home/travis/build/simonagren/simonagren.github.io/content/posts/2018-11-07--hello-world/index.md absPath of file >>> MarkdownRemark",html:'<p>\n  <a\n    class="gatsby-resp-image-link"\n    href="/static/photo-1465070845512-2b2dbdc6df66-c05f925825606e19a957283ac76dc0db-314f0.jpg"\n    style="display: block"\n    target="_blank"\n    rel="noopener"\n  >\n  \n  <span\n    class="gatsby-resp-image-wrapper"\n    style="position: relative; display: block; ; max-width: 800px; margin-left: auto; margin-right: auto;"\n  >\n    <span\n      class="gatsby-resp-image-background-image"\n      style="padding-bottom: 62.02185792349726%; position: relative; bottom: 0; left: 0; background-image: url(\'data:image/jpeg;base64,\'); background-size: cover; display: block;"\n    >\n      <img\n        class="gatsby-resp-image-image"\n        style="width: 100%; height: 100%; margin: 0; vertical-align: middle; position: absolute; top: 0; left: 0; box-shadow: inset 0px 0px 0px 400px transparent;"\n        alt="photo 1465070845512 2b2dbdc6df66"\n        title=""\n        src="/static/photo-1465070845512-2b2dbdc6df66-c05f925825606e19a957283ac76dc0db-78f2b.jpg"\n        srcset="/static/photo-1465070845512-2b2dbdc6df66-c05f925825606e19a957283ac76dc0db-dce19.jpg 200w,\n/static/photo-1465070845512-2b2dbdc6df66-c05f925825606e19a957283ac76dc0db-c1413.jpg 400w,\n/static/photo-1465070845512-2b2dbdc6df66-c05f925825606e19a957283ac76dc0db-78f2b.jpg 800w,\n/static/photo-1465070845512-2b2dbdc6df66-c05f925825606e19a957283ac76dc0db-ab4c4.jpg 1200w,\n/static/photo-1465070845512-2b2dbdc6df66-c05f925825606e19a957283ac76dc0db-314f0.jpg 1464w"\n        sizes="(max-width: 800px) 100vw, 800px"\n      />\n    </span>\n  </span>\n  \n  </a>\n    </p>\n<h3>A new start</h3>\n<p>So this is my first blog post. Hello world! </p>\n<p>I have worked some with a starter template and it is built in <code class="language-text">GatsbyJS</code>. So this is static pages composed with markdown, and some <code class="language-text">React</code> involved as well.</p>\n<h3>So what’s next?</h3>\n<p>I’m currently preparing some internal educational material to use within our company, and it involves preparing a few demoes. I diving in to Flow and PowerApps currently, so don’t be surprised if I blog about some of the concepts.</p>\n<h3>Why am I doing this?</h3>\n<p>I want try out blogging, I feel that it’s a good way to collect my thoughts regarding the challenges I face in my work. It might be useful for anyone, and maybe I will remember the solutions better next time.</p>\n<p>And I plan to start with real blog post quite soon.</p>',fields:{slug:"/hello-world/",prefix:"2018-11-07"},frontmatter:{title:"Hello World - a first blog post",author:"Simon Ågren",category:null,tags:["gatsby"],cover:{childImageSharp:{resize:{src:"/static/photo-1465070845512-2b2dbdc6df66-c05f925825606e19a957283ac76dc0db-ada8c.jpg"}}}}},authornote:{id:"/home/travis/build/simonagren/simonagren.github.io/content/parts/author.md absPath of file >>> MarkdownRemark",html:"<p><strong>Simon Ågren</strong> Passionate about SharePoint and Office365. Solution Architect working as a consultant for Sogeti in Umeå, Sweden.</p>"},site:{siteMetadata:{facebook:{appId:"2263145610597628"}}}},pathContext:{slug:"/hello-world/",prev:{id:"/home/travis/build/simonagren/simonagren.github.io/content/posts/draft-post/index.md absPath of file >>> MarkdownRemark",fields:{slug:"/draft-post/",prefix:null},frontmatter:{title:"This is a draft post",category:"sayings",tags:null}},next:{id:"/home/travis/build/simonagren/simonagren.github.io/content/posts/2018-11-08--create-team-site-script/index.md absPath of file >>> MarkdownRemark",fields:{slug:"/create-team-site-script/",prefix:"2018-11-08"},frontmatter:{title:"Create a Microsoft Team using site scripts, Flow and Hub Sites",category:null,tags:["flow","sharepoint","sitescripts","pnp"]}}}}}});
